    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )


def _dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]


def _mag(v):
    return math.sqrt(_dot(v, v))


def _normalize(v):
    m = _mag(v)
    if m <= EPS:
        return (0.0, 0.0, 0.0)
    return (v[0] / m, v[1] / m, v[2] / m)


def _triangle_normal(v1, v2, v3):
    return _cross(_sub(v2, v1), _sub(v3, v1))


def _triangle_area(v1, v2, v3):
    return 0.5 * _mag(_triangle_normal(v1, v2, v3))


def _is_binary_stl(data):
    if len(data) < 84:
        return False
    tri_count = struct.unpack_from('<I', data, 80)[0]
    expected = 84 + tri_count * 50
    if expected == len(data):
        return True
    if not data[:5].lower() == b'solid':
        return True
    try:
        text = data.decode('utf-8')
    except UnicodeDecodeError:
        return True
    stripped = text.lstrip()
    return not stripped.startswith('solid')


